var apiDashboardSearchLookmlDashboardsCmd = &cobra.Command{
	Use:   "search_lookml_dashboards",
	Short: "Search LookML Dashboards",
	Long:  "### Search LookML Dashboards\n\nReturns an array of **LookML Dashboard** objects that match the specified search criteria.\nNote, this only returns LookML Dashboards in production.\n\nIf multiple search params are given and `filter_or` is FALSE or not specified,\nsearch params are combined in a logical AND operation.\nOnly rows that match *all* search param criteria will be returned.\n\nIf `filter_or` is TRUE, multiple search params are combined in a logical OR operation.\nResults will include rows that match **any** of the search criteria.\n\nString search params use case-insensitive matching.\nString search params can contain `%` and '_' as SQL LIKE pattern match wildcard expressions.\nexample=\"dan%\" will match \"danger\" and \"Danzig\" but not \"David\"\nexample=\"D_m%\" will match \"Damage\" and \"dump\"\n\nInteger search params can accept a single value or a comma separated list of values. The multiple\nvalues will be combined under a logical OR operation - results will match at least one of\nthe given values.\n\nMost search params can accept \"IS NULL\" and \"NOT NULL\" as special expressions to match\nor exclude (respectively) rows where the column is null.\n\nBoolean search params accept only \"true\" and \"false\" as values.\n\n\nThe parameters `limit`, and `offset` are recommended for fetching results in page-size chunks.\n\nGet a **single LookML dashboard** by id with [dashboard_lookml()](#!/Dashboard/dashboard_lookml)\n",
	Args:  cobra.ExactArgs(0),
	RunE: func(cmd *cobra.Command, args []string) error {
		queryParams := make(map[string]string)
		if cmd.Flags().Changed("content_favorite_id") {
			val, _ := cmd.Flags().GetString("content_favorite_id")
			queryParams["content_favorite_id"] = val
		}
		if cmd.Flags().Changed("fields") {
			val, _ := cmd.Flags().GetString("fields")
			queryParams["fields"] = val
		}
		if cmd.Flags().Changed("folder_id") {
			val, _ := cmd.Flags().GetString("folder_id")
			queryParams["folder_id"] = val
		}
		if cmd.Flags().Changed("limit") {
			val, _ := cmd.Flags().GetString("limit")
			queryParams["limit"] = val
		}
		if cmd.Flags().Changed("offset") {
			val, _ := cmd.Flags().GetString("offset")
			queryParams["offset"] = val
		}
		if cmd.Flags().Changed("sorts") {
			val, _ := cmd.Flags().GetString("sorts")
			queryParams["sorts"] = val
		}
		if cmd.Flags().Changed("title") {
			val, _ := cmd.Flags().GetString("title")
			queryParams["title"] = val
		}
		return executeApiCallGeneric(cmd, "GET", "/dashboards/lookml/search", []string{}, []string{}, "", queryParams, args)
	},
}

