var apiThemeSearchThemesCmd = &cobra.Command{
	Use:   "search_themes",
	Short: "Search Themes",
	Long:  "### Search all themes for matching criteria.\n\nReturns an **array of theme objects** that match the specified search criteria.\n\n| Search Parameters | Description\n| :-------------------: | :------ |\n| `begin_at` only | Find themes active at or after `begin_at`\n| `end_at` only | Find themes active at or before `end_at`\n| both set | Find themes with an active inclusive period between `begin_at` and `end_at`\n\nNote: Range matching requires boolean AND logic.\nWhen using `begin_at` and `end_at` together, do not use `filter_or`=TRUE\n\nIf multiple search params are given and `filter_or` is FALSE or not specified,\nsearch params are combined in a logical AND operation.\nOnly rows that match *all* search param criteria will be returned.\n\nIf `filter_or` is TRUE, multiple search params are combined in a logical OR operation.\nResults will include rows that match **any** of the search criteria.\n\nString search params use case-insensitive matching.\nString search params can contain `%` and '_' as SQL LIKE pattern match wildcard expressions.\nexample=\"dan%\" will match \"danger\" and \"Danzig\" but not \"David\"\nexample=\"D_m%\" will match \"Damage\" and \"dump\"\n\nInteger search params can accept a single value or a comma separated list of values. The multiple\nvalues will be combined under a logical OR operation - results will match at least one of\nthe given values.\n\nMost search params can accept \"IS NULL\" and \"NOT NULL\" as special expressions to match\nor exclude (respectively) rows where the column is null.\n\nBoolean search params accept only \"true\" and \"false\" as values.\n\n\nGet a **single theme** by id with [Theme](#!/Theme/theme)\n\n**Note**: Custom themes needs to be enabled by Looker. Unless custom themes are enabled, only the automatically generated default theme can be used. Please contact your Account Manager or https://console.cloud.google.com/support/cases/ to update your license for this feature.\n\n",
	Args:  cobra.ExactArgs(0),
	RunE: func(cmd *cobra.Command, args []string) error {
		queryParams := make(map[string]string)
		if cmd.Flags().Changed("begin_at") {
			val, _ := cmd.Flags().GetString("begin_at")
			queryParams["begin_at"] = val
		}
		if cmd.Flags().Changed("end_at") {
			val, _ := cmd.Flags().GetString("end_at")
			queryParams["end_at"] = val
		}
		if cmd.Flags().Changed("fields") {
			val, _ := cmd.Flags().GetString("fields")
			queryParams["fields"] = val
		}
		if cmd.Flags().Changed("filter_or") {
			val, _ := cmd.Flags().GetBool("filter_or")
			queryParams["filter_or"] = strconv.FormatBool(val)
		}
		if cmd.Flags().Changed("id") {
			val, _ := cmd.Flags().GetString("id")
			queryParams["id"] = val
		}
		if cmd.Flags().Changed("limit") {
			val, _ := cmd.Flags().GetString("limit")
			queryParams["limit"] = val
		}
		if cmd.Flags().Changed("name") {
			val, _ := cmd.Flags().GetString("name")
			queryParams["name"] = val
		}
		if cmd.Flags().Changed("offset") {
			val, _ := cmd.Flags().GetString("offset")
			queryParams["offset"] = val
		}
		if cmd.Flags().Changed("sorts") {
			val, _ := cmd.Flags().GetString("sorts")
			queryParams["sorts"] = val
		}
		return executeApiCallGeneric(cmd, "GET", "/themes/search", []string{}, []string{}, "", queryParams, args)
	},
}

