	apiThemeCmd.AddCommand(apiThemeSearchThemesCmd)
	apiThemeSearchThemesCmd.Flags().String("begin_at", "", "Timestamp for activation.")
	apiThemeSearchThemesCmd.Flags().String("end_at", "", "Timestamp for expiration.")
