var apiWorkspaceWorkspaceCmd = &cobra.Command{
	Use:   "workspace [WORKSPACE_ID]",
	Short: "Get Workspace",
	Long:  "### Get A Workspace\n\nReturns information about a workspace such as the git status and selected branches\nof all projects available to the caller's user account.\n\nA workspace defines which versions of project files will be used to evaluate expressions\nand operations that use model definitions - operations such as running queries or rendering dashboards.\nEach project has its own git repository, and each project in a workspace may be configured to reference\nparticular branch or revision within their respective repositories.\n\nThere are two predefined workspaces available: \"production\" and \"dev\".\n\nThe production workspace is shared across all Looker users. Models in the production workspace are read-only.\nChanging files in production is accomplished by modifying files in a git branch and using Pull Requests\nto merge the changes from the dev branch into the production branch, and then telling\nLooker to sync with production.\n\nThe dev workspace is local to each Looker user. Changes made to project/model files in the dev workspace only affect\nthat user, and only when the dev workspace is selected as the active workspace for the API session.\n(See set_session_workspace()).\n\nThe dev workspace is NOT unique to an API session. Two applications accessing the Looker API using\nthe same user account will see the same files in the dev workspace. To avoid collisions between\nAPI clients it's best to have each client login with API credentials for a different user account.\n\nChanges made to files in a dev workspace are persistent across API sessions. It's a good\nidea to commit any changes you've made to the git repository, but not strictly required. Your modified files\nreside in a special user-specific directory on the Looker server and will still be there when you login in again\nlater and use update_session(workspace_id: \"dev\") to select the dev workspace for the new API session.\n",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		queryParams := make(map[string]string)
		return executeApiCallGeneric(cmd, "GET", "/workspaces/{workspace_id}", []string{"workspace_id"}, []string{}, "", queryParams, args)
	},
}

func init() {
	apiWorkspaceCmd.AddCommand(apiWorkspaceWorkspaceCmd)
}

func executeApiCallGeneric(cmd *cobra.Command, method, pathTemplate string, pathParams, requiredQueryParams []string, bodyParam string, queryParams map[string]string, args []string) error {
	ctx := cmd.Context()
	c, err := initClient(ctx, false)
	if err != nil {
		return err
	}

	actualPath := pathTemplate
	argIdx := 0

	// 1. Replace path parameters
	for _, paramName := range pathParams {
		if argIdx >= len(args) {
			return fmt.Errorf("missing required path parameter: %s", paramName)
		}
		val := args[argIdx]
		argIdx++
		actualPath = strings.ReplaceAll(actualPath, "{"+paramName+"}", url.PathEscape(val))
	}

	// 2. Parse required query parameters
	qParams := make(map[string]string)
	for _, paramName := range requiredQueryParams {
		if argIdx >= len(args) {
			return fmt.Errorf("missing required query parameter: %s", paramName)
		}
		val := args[argIdx]
		argIdx++
		qParams[paramName] = val
	}

	// 3. Parse body parameter
	var bodyReader io.Reader
	if bodyParam != "" {
		if argIdx >= len(args) {
			return fmt.Errorf("missing required body parameter (JSON file path or '-' for stdin)")
		}
		bodyFile := args[argIdx]
		argIdx++

		var bodyBytes []byte
		if bodyFile == "-" {
			bodyBytes, err = io.ReadAll(os.Stdin)
		} else {
			bodyBytes, err = os.ReadFile(bodyFile)
		}
		if err != nil {
			return fmt.Errorf("failed to read body from %s: %w", bodyFile, err)
		}
		bodyReader = bytes.NewReader(bodyBytes)
	}

	// 4. Construct URL
	u, err := url.Parse(c.Session.Config.BaseUrl)
	if err != nil {
		return fmt.Errorf("invalid base URL: %w", err)
	}
	u.Path = "/api/4.0" + actualPath

	q := u.Query()
	// Set required query params
	for k, v := range qParams {
		q.Set(k, v)
	}
	// Set optional query params from flags
	for k, v := range queryParams {
		q.Set(k, v)
	}
	u.RawQuery = q.Encode()

	// 5. Create HTTP request
	req, err := http.NewRequestWithContext(ctx, method, u.String(), bodyReader)
	if err != nil {
		return fmt.Errorf("failed to create request: %w", err)
	}
	if bodyReader != nil {
		req.Header.Set("Content-Type", "application/json")
	}

	// 6. Execute request
	resp, err := c.Session.Client.Do(req)
	if err != nil {
		return fmt.Errorf("API request failed: %w", err)
	}
	defer func() { _ = resp.Body.Close() }()

	// 7. Read response
	outBytes, err := io.ReadAll(resp.Body)
	if err != nil {
		return fmt.Errorf("failed to read response body: %w", err)
	}

	if resp.StatusCode >= 400 {
		return fmt.Errorf("API returned error %s: %s", resp.Status, string(outBytes))
	}

	fmt.Println(string(outBytes))
	return nil
}
